{ title: "Check-in σε ξενοδοχείο στην Αγία Πετρούπολη", scene: "Φτάνεις σε ξενοδοχείο κοντά στο κέντρο της Αγίας Πετρούπολης. Έχεις κράτηση και θέλεις να μάθεις για το πρωινό και το ασανσέρ.", lines: [{ who: "them", ru: "Добрый вечер, добро пожаловать.", el: "Καλησπέρα, καλώς ήρθατε." }, { who: "you", ru: "Добрый вечер, у меня есть бронирование.", el: "Καλησπέρα, έχω κράτηση." }, { who: "them", ru: "На какое имя?", el: "Σε ποιο όνομα;" }, { who: "you", ru: "На имя Пападопулос.", el: "Στο όνομα Παπαδόπουλος." }, { who: "them", ru: "Можно ваш паспорт?", el: "Μπορώ να έχω το διαβατήριό σας;" }, { who: "you", ru: "Вот мой паспорт.", el: "Ορίστε το διαβατήριό μου." }, { who: "them", ru: "Ваш номер на пятом этаже.", el: "Το δωμάτιό σας είναι στον πέμπτο όροφο." }, { who: "you", ru: "Завтрак включён?", el: "Περιλαμβάνεται πρωινό;" }, { who: "them", ru: "Да, завтрак с семи до десяти.", el: "Ναι, το πρωινό είναι από τις επτά ως τις δέκα." }, { who: "you", ru: "Где лифт?", el: "Πού είναι το ασανσέρ;" }, { who: "them", ru: "Лифт справа.", el: "Το ασανσέρ είναι δεξιά." }, { who: "you", ru: "Спасибо за помощь.", el: "Ευχαριστώ για τη βοήθεια." }] },
{ title: "Ζητώντας οδηγίες για μουσείο", scene: "Περπατάς στο κέντρο της πόλης και ψάχνεις ένα μουσείο. Σταματάς έναν περαστικό και ζητάς οδηγίες με ευγενικό τρόπο.", lines: [{ who: "you", ru: "Извините, пожалуйста.", el: "Συγγνώμη, παρακαλώ." }, { who: "them", ru: "Да, слушаю.", el: "Ναι, σας ακούω." }, { who: "you", ru: "Где музей?", el: "Πού είναι το μουσείο;" }, { who: "them", ru: "Идите прямо, потом налево.", el: "Πηγαίνετε ευθεία, μετά αριστερά." }, { who: "you", ru: "Это далеко?", el: "Είναι μακριά;" }, { who: "them", ru: "Нет, это рядом.", el: "Όχι, είναι κοντά." }, { who: "you", ru: "Сколько минут пешком?", el: "Πόσα λεπτά με τα πόδια;" }, { who: "them", ru: "Примерно десять минут.", el: "Περίπου δέκα λεπτά." }, { who: "you", ru: "Спасибо большое.", el: "Ευχαριστώ πολύ." }, { who: "them", ru: "Пожалуйста.", el: "Παρακαλώ." }, { who: "you", ru: "До свидания.", el: "Αντίο." }, { who: "them", ru: "До свидания.", el: "Αντίο." }] },
{ title: "Δείπνο σε ρωσικό εστιατόριο", scene: "Μπαίνεις σε εστιατόριο στη Μόσχα για δείπνο. Θέλεις τραπέζι για δύο, μια πρόταση από τον σερβιτόρο και κάτι όχι πικάντικο.", lines: [{ who: "them", ru: "Добрый вечер, у вас есть бронь?", el: "Καλησπέρα, έχετε κράτηση;" }, { who: "you", ru: "Нет, стол на двоих, пожалуйста.", el: "Όχι, τραπέζι για δύο, παρακαλώ." }, { who: "them", ru: "Конечно, проходите.", el: "Φυσικά, περάστε." }, { who: "you", ru: "Можно меню?", el: "Μπορώ να έχω το μενού;" }, { who: "them", ru: "Да, пожалуйста.", el: "Ναι, ορίστε." }, { who: "you", ru: "Что вы рекомендуете?", el: "Τι προτείνετε;" }, { who: "them", ru: "Рекомендую суп и рыбу.", el: "Προτείνω σούπα και ψάρι." }, { who: "you", ru: "Хорошо, я хочу суп, не остро.", el: "Ωραία, θέλω σούπα, όχι πικάντικη." }, { who: "them", ru: "Конечно, что будете пить?", el: "Φυσικά, τι θα πιείτε;" }, { who: "you", ru: "Воду, пожалуйста.", el: "Νερό, παρακαλώ." }, { who: "them", ru: "Хорошо.", el: "Εντάξει." }, { who: "you", ru: "Спасибо.", el: "Ευχαριστώ." }] },
{ title: "Αγορά εισιτηρίου μετρό", scene: "Βρίσκεσαι στο μετρό της Μόσχας και θέλεις να αγοράσεις εισιτήριο. Ρωτάς στο ταμείο για κάρτα μετακίνησης και τη σωστή γραμμή.", lines: [{ who: "them", ru: "Здравствуйте.", el: "Γεια σας." }, { who: "you", ru: "Здравствуйте, один билет на метро, пожалуйста.", el: "Γεια σας, ένα εισιτήριο για το μετρό, παρακαλώ." }, { who: "them", ru: "Один билет или карта Тройка?", el: "Ένα εισιτήριο ή κάρτα Τρόικα;" }, { who: "you", ru: "Мне нужна карта Тройка.", el: "Χρειάζομαι κάρτα Τρόικα." }, { who: "them", ru: "На сколько поездок?", el: "Για πόσες διαδρομές;" }, { who: "you", ru: "На десять поездок, пожалуйста.", el: "Για δέκα διαδρομές, παρακαλώ." }, { who: "them", ru: "Оплата картой?", el: "Πληρωμή με κάρτα;" }, { who: "you", ru: "Да, можно оплатить картой?", el: "Ναι, μπορώ να πληρώσω με κάρτα;" }, { who: "them", ru: "Да, конечно.", el: "Ναι, φυσικά." }, { who: "you", ru: "Какая линия в центр?", el: "Ποια γραμμή πάει στο κέντρο;" }, { who: "them", ru: "Синяя линия, платформа справа.", el: "Η μπλε γραμμή, πλατφόρμα δεξιά." }, { who: "you", ru: "Спасибо большое.", el: "Ευχαριστώ πολύ." }] },
{ title: "Αγορά σουβενίρ", scene: "Είσαι σε κατάστημα σουβενίρ και ψάχνεις δώρο. Θέλεις να ρωτήσεις τιμή, χρώμα και αν υπάρχει κάτι φθηνότερο.", lines: [{ who: "them", ru: "Здравствуйте, вам помочь?", el: "Γεια σας, να σας βοηθήσω;" }, { who: "you", ru: "Здравствуйте, я ищу подарок.", el: "Γεια σας, ψάχνω δώρο." }, { who: "them", ru: "Посмотрите эти сувениры.", el: "Κοιτάξτε αυτά τα σουβενίρ." }, { who: "you", ru: "Сколько это стоит?", el: "Πόσο κοστίζει αυτό;" }, { who: "them", ru: "Это стоит тысячу рублей.", el: "Αυτό κοστίζει χίλια ρούβλια." }, { who: "you", ru: "Это слишком дорого.", el: "Αυτό είναι πολύ ακριβό." }, { who: "them", ru: "Есть дешевле.", el: "Υπάρχει φθηνότερο." }, { who: "you", ru: "Есть синий цвет?", el: "Υπάρχει μπλε χρώμα;" }, { who: "them", ru: "Да, вот синий.", el: "Ναι, ορίστε το μπλε." }, { who: "you", ru: "Хорошо, я беру это.", el: "Ωραία, θα πάρω αυτό." }, { who: "them", ru: "Нужен пакет?", el: "Χρειάζεστε σακούλα;" }, { who: "you", ru: "Да, пожалуйста.", el: "Ναι, παρακαλώ." }] },
{ title: "Στο φαρμακείο για πονοκέφαλο", scene: "Έχεις πονοκέφαλο και μπαίνεις σε φαρμακείο. Θέλεις απλό φάρμακο και αναφέρεις ότι έχεις αλλεργία.", lines: [{ who: "them", ru: "Здравствуйте, что вам нужно?", el: "Γεια σας, τι χρειάζεστε;" }, { who: "you", ru: "Здравствуйте, у меня болит голова.", el: "Γεια σας, με πονάει το κεφάλι." }, { who: "them", ru: "Вам нужно лекарство от боли?", el: "Χρειάζεστε φάρμακο για τον πόνο;" }, { who: "you", ru: "Да, пожалуйста.", el: "Ναι, παρακαλώ." }, { who: "them", ru: "У вас есть аллергия?", el: "Έχετε αλλεργία;" }, { who: "you", ru: "Да, у меня аллергия.", el: "Ναι, έχω αλλεργία." }, { who: "them", ru: "На что аллергия?", el: "Σε τι έχετε αλλεργία;" }, { who: "you", ru: "Я не знаю по-русски.", el: "Δεν ξέρω στα ρωσικά." }, { who: "them", ru: "Понимаю, говорите медленно.", el: "Καταλαβαίνω, μιλήστε αργά." }, { who: "you", ru: "Можно безопасное лекарство?", el: "Μπορώ να έχω ασφαλές φάρμακο;" }, { who: "them", ru: "Да, вот это.", el: "Ναι, αυτό εδώ." }, { who: "you", ru: "Спасибо за помощь.", el: "Ευχαριστώ για τη βοήθεια." }] },
{ title: "Μικρή συζήτηση με ντόπιο σε τρένο", scene: "Ταξιδεύεις με τρένο από Μόσχα προς Αγία Πετρούπολη. Ένας ντόπιος κάθεται απέναντί σου και ξεκινάτε μια απλή, φιλική συζήτηση.", lines: [{ who: "you", ru: "Здравствуйте, это моё место?", el: "Γεια σας, είναι αυτή η θέση μου;" }, { who: "them", ru: "Да, ваше место здесь.", el: "Ναι, η θέση σας είναι εδώ." }, { who: "you", ru: "Спасибо. Я из Греции.", el: "Ευχαριστώ. Είμαι από την Ελλάδα." }, { who: "them", ru: "Очень приятно, я из Москвы.", el: "Χάρηκα πολύ, είμαι από τη Μόσχα." }, { who: "you", ru: "Очень приятно познакомиться.", el: "Χάρηκα πολύ για τη γνωριμία." }, { who: "them", ru: "Вам нравится Россия?", el: "Σας αρέσει η Ρωσία;" }, { who: "you", ru: "Да, мне нравится город и еда.", el: "Ναι, μου αρέσει η πόλη και το φαγητό." }, { who: "them", ru: "Петербург очень красивый.", el: "Η Πετρούπολη είναι πολύ όμορφη." }, { who: "you", ru: "Я хочу увидеть музей.", el: "Θέλω να δω μουσείο." }, { who: "them", ru: "Тогда идите в Эрмитаж.", el: "Τότε πηγαίνετε στο Ερμιτάζ." }, { who: "you", ru: "Спасибо, это интересно.", el: "Ευχαριστώ, αυτό είναι ενδιαφέρον." }, { who: "them", ru: "Хорошей поездки!", el: "Καλό ταξίδι!" }] }
